// deno-lint-ignore no-explicit-any
export function getPostBySlug(slug: string): any {
  // deno-lint-ignore no-explicit-any
  return posts.find((p: any) => p.slug === slug);
}

export function getBlogOptions() {
  return { contentDir: "content/blog", basePath: "/blog" };
}
